// This implementation uses PROPER signature verification with jwks-rsa.

const express = require('express');
const session = require('express-session');
const jwt = require('jsonwebtoken');
const jwksRsa = require('jwks-rsa');
const { Issuer, generators } = require('openid-client');
const crypto = require('crypto');

const app = express();

// Configuration - replace with your OpenID Connect provider details
const config = {
  issuer: process.env.OIDC_ISSUER || 'https://your-oidc-provider.com',
  clientId: process.env.OIDC_CLIENT_ID || 'your-client-id',
  clientSecret: process.env.OIDC_CLIENT_SECRET || 'your-client-secret',
  redirectUri: process.env.OIDC_REDIRECT_URI || 'http://localhost:3000/callback',
  scope: 'openid profile email',
  sessionSecret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
};

// Session middleware
app.use(session({
  secret: config.sessionSecret,
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production', // HTTPS in production
    httpOnly: true,
    maxAge: 3600000, // 1 hour
    sameSite: 'lax',
  },
}));

// JWKS client for fetching signing keys from the provider
const jwksClient = jwksRsa({
  jwksUri: `${config.issuer}/.well-known/jwks.json`,
  cache: true,
  cacheMaxEntries: 5,
  cacheMaxAge: 600000, // 10 minutes
  rateLimit: true,
  jwksRequestsPerMinute: 10,
});

// Function to get the signing key from JWKS endpoint
function getSigningKey(header) {
  return new Promise((resolve, reject) => {
    jwksClient.getSigningKey(header.kid, (err, key) => {
      if (err) {
        reject(err);
        return;
      }
      const signingKey = key.getPublicKey();
      resolve(signingKey);
    });
  });
}

// SECURE: Verify the JWT ID token with full signature verification
async function verifyIdToken(idToken) {
  // First, decode the header (without verification) just to get the kid
  const decodedHeader = jwt.decode(idToken, { complete: true });
  if (!decodedHeader) {
    throw new Error('Invalid JWT: unable to decode token');
  }

  // Fetch the signing key from the JWKS endpoint
  const signingKey = await getSigningKey(decodedHeader.header);

  // VERIFY the token with signature check and all standard claims
  const verified = jwt.verify(idToken, signingKey, {
    algorithms: ['RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512'],
    issuer: config.issuer,
    audience: config.clientId,
    clockTolerance: 30, // 30 seconds tolerance for clock skew
  });

  return verified;
}

// Extract and validate user claims from verified token
function extractUserClaims(verifiedToken) {
  return {
    sub: verifiedToken.sub,            // Subject (unique user identifier)
    email: verifiedToken.email || null,
    emailVerified: verifiedToken.email_verified || false,
    name: verifiedToken.name || null,
    givenName: verifiedToken.given_name || null,
    familyName: verifiedToken.family_name || null,
    picture: verifiedToken.picture || null,
    locale: verifiedToken.locale || null,
    iat: verifiedToken.iat,
    exp: verifiedToken.exp,
    nonce: verifiedToken.nonce || null,
  };
}

// Middleware to check if user is authenticated
function requireAuth(req, res, next) {
  if (req.session && req.session.user) {
    // Check if the session has expired based on token expiry
    const now = Math.floor(Date.now() / 1000);
    if (req.session.user.exp && now > req.session.user.exp) {
      req.session.destroy();
      return res.redirect('/login');
    }
    return next();
  }
  res.redirect('/login');
}

let oidcClient = null;

// Initialize OpenID Connect client
async function initializeOIDC() {
  try {
    const issuer = await Issuer.discover(config.issuer);
    console.log('Discovered issuer:', issuer.metadata.issuer);

    oidcClient = new issuer.Client({
      client_id: config.clientId,
      client_secret: config.clientSecret,
      redirect_uris: [config.redirectUri],
      response_types: ['code'],
      token_endpoint_auth_method: 'client_secret_basic',
    });

    console.log('OIDC client initialized successfully');
  } catch (err) {
    console.error('Failed to initialize OIDC client:', err.message);
    throw err;
  }
}

